{
  "name": "Nexus Research Agent",
  "description": "A multimodal research workspace with persistent context and adaptive reasoning modes.",
  "requestFramePermissions": [
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type ArtifactType = 'text' | 'image' | 'csv' | 'audio';

export interface Artifact {
  id: string;
  name: string;
  type: ArtifactType;
  content: string; // Text content or Base64 string
  mimeType?: string;
  createdAt: number;
}

export type Role = 'user' | 'model';

export interface Message {
  id: string;
  role: Role;
  text: string;
  timestamp: number;
  relatedArtifactIds?: string[]; // IDs of artifacts referenced or used
  isThinking?: boolean; // For UI state
}

export type ReasoningMode = 'flash' | 'pro';

export interface ChatState {
  messages: Message[];
  isProcessing: boolean;
  mode: ReasoningMode;
}

export interface CsvData {
  headers: string[];
  rows: Record<string, string | number>[];
}

import { openDB, DBSchema, IDBPDatabase } from 'idb';
import { Artifact } from '../types';

interface NexusDB extends DBSchema {
  artifacts: {
    key: string;
    value: Artifact;
  };
}

const DB_NAME = 'nexus-db';
const STORE_NAME = 'artifacts';

let dbPromise: Promise<IDBPDatabase<NexusDB>> | null = null;

const getDB = () => {
  if (!dbPromise) {
    dbPromise = openDB<NexusDB>(DB_NAME, 1, {
      upgrade(db) {
        if (!db.objectStoreNames.contains(STORE_NAME)) {
          db.createObjectStore(STORE_NAME, { keyPath: 'id' });
        }
      },
    });
  }
  return dbPromise;
};

export const saveArtifact = async (artifact: Artifact): Promise<void> => {
  const db = await getDB();
  await db.put(STORE_NAME, artifact);
};

export const getAllArtifacts = async (): Promise<Artifact[]> => {
  const db = await getDB();
  return db.getAll(STORE_NAME);
};

export const deleteArtifact = async (id: string): Promise<void> => {
  const db = await getDB();
  await db.delete(STORE_NAME, id);
};

export const clearArtifacts = async (): Promise<void> => {
    const db = await getDB();
    await db.clear(STORE_NAME);
}

import { GoogleGenAI, Type } from "@google/genai";
import { Artifact, Message, ReasoningMode } from "../types";

// Helper to get fresh client instance to ensure latest key is used if it changes (though env key is static here)
const getClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

// System instruction for Nexus
const SYSTEM_INSTRUCTION = `
You are Nexus, a research agent designed to synthesize information across persistent, multimodal context.
Your role is to assist with complex analytical tasks by reasoning over documents, structured data, images, and prior outputs that exist in the current session’s memory.
Treat this memory as an evolving research workspace.

Core Behavior:
- Maintain continuity.
- Prefer explicit reasoning grounded in provided materials.
- When making claims, reference relevant files or visual artifacts.
- Distinguish between correlation, causation, and hypothesis.

Reasoning Modes:
- Flash mode: Prioritize speed, summarization, extraction.
- Pro mode: Prioritize depth, multi-step reasoning, synthesis.
`;

export const generateResponse = async (
  history: Message[],
  artifacts: Artifact[],
  mode: ReasoningMode,
  lastUserMessage: string
): Promise<string> => {
  const ai = getClient();

  // 1. Select Model
  let modelName = 'gemini-3-flash-preview';
  if (mode === 'pro') {
    modelName = 'gemini-3-pro-preview';
  }

  // 2. Prepare Context (Artifacts)
  // We attach artifacts to the current turn or system instruction context.
  // For simplicity and effectiveness, we will append them to the prompt content as "Context parts".

  const contentParts: any[] = [];

  // Add artifacts
  if (artifacts.length > 0) {
    contentParts.push({ text: "--- AVAILABLE RESEARCH CONTEXT ---" });
    for (const art of artifacts) {
        if (art.type === 'image' && art.mimeType) {
            contentParts.push({ text: `[Image: ${art.name}]` });
            contentParts.push({
                inlineData: {
                    mimeType: art.mimeType,
                    data: art.content // Base64
                }
            });
        } else if (art.type === 'csv' || art.type === 'text') {
            contentParts.push({ text: `[File: ${art.name}]\n${art.content}\n---` });
        }
    }
    contentParts.push({ text: "--- END CONTEXT ---\n" });
  }

  // Add User Message
  contentParts.push({ text: lastUserMessage });

  // 3. Configure Tools
  const tools: any[] = [];
  // Enable Google Search for Flash mode if relevant for retrieval
  if (mode === 'flash') {
      tools.push({ googleSearch: {} });
  }

  // 4. Configure Thinking (Pro Mode only)
  let thinkingConfig = undefined;
  if (mode === 'pro') {
      thinkingConfig = { thinkingBudget: 2048 };
  }

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: {
        role: 'user',
        parts: contentParts
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        tools: tools.length > 0 ? tools : undefined,
        thinkingConfig: thinkingConfig,
      }
    });

    let finalText = response.text || "";

    // Append grounding info if available
    if (response.candidates?.[0]?.groundingMetadata?.groundingChunks) {
        const chunks = response.candidates[0].groundingMetadata.groundingChunks;
        const links = chunks
            .map((c: any) => c.web?.uri ? `[${c.web.title || 'Source'}](${c.web.uri})` : null)
            .filter(Boolean)
            .join(', ');
        if (links) {
            finalText += `\n\n*Sources: ${links}*`;
        }
    }

    return finalText;
  } catch (error: any) {
    console.error("Gemini API Error:", error);
    return `Error: ${error.message || "Unknown error occurred during reasoning."}`;
  }
};

export const transcribeAudio = async (base64Audio: string, mimeType: string): Promise<string> => {
    const ai = getClient();
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: {
                parts: [
                    {
                        inlineData: {
                            mimeType: mimeType,
                            data: base64Audio
                        }
                    },
                    { text: "Transcribe this audio exactly as spoken." }
                ]
            }
        });
        return response.text || "";
    } catch (e) {
        console.error("Transcription error", e);
        throw e;
    }
}

export const analyzeImageDetailed = async (base64Image: string, mimeType: string, prompt: string) => {
    const ai = getClient();
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-pro-preview', // Required for detailed analysis
            contents: {
                parts: [
                    {
                        inlineData: {
                            mimeType: mimeType,
                            data: base64Image
                        }
                    },
                    { text: prompt }
                ]
            }
        });
        return response.text || "";
    } catch (e) {
        console.error("Image analysis error", e);
        throw e;
    }
}

import React, { useMemo } from 'react';
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  BarChart,
  Bar,
  Legend
} from 'recharts';
import { Artifact } from '../types';

// Simple CSV parser
const parseCSV = (content: string) => {
    const lines = content.trim().split('\n');
    if (lines.length < 2) return null;
    const headers = lines[0].split(',').map(h => h.trim());
    const data = lines.slice(1).map(line => {
        const values = line.split(',');
        const obj: any = {};
        headers.forEach((h, i) => {
            const val = values[i]?.trim();
            // Try convert to number
            const num = parseFloat(val);
            obj[h] = isNaN(num) ? val : num;
        });
        return obj;
    });
    return { headers, data };
};

interface ChartRendererProps {
    artifact: Artifact;
}

export const ChartRenderer: React.FC<ChartRendererProps> = ({ artifact }) => {
    const chartData = useMemo(() => parseCSV(artifact.content), [artifact.content]);

    if (!chartData || chartData.data.length === 0) return <div className="text-nexus-500 text-xs italic">Invalid Data</div>;

    const keys = chartData.headers;
    const xKey = keys[0]; // Assume first column is X-axis (e.g. date)
    const dataKeys = keys.slice(1).filter(k => typeof chartData.data[0][k] === 'number');

    if (dataKeys.length === 0) return <div className="text-nexus-500 text-xs italic">No numeric data to chart</div>;

    // Use BarChart for few items, LineChart for many
    const ChartComponent = chartData.data.length < 20 ? BarChart : LineChart;
    const DataComponent = chartData.data.length < 20 ? Bar : Line;

    return (
        <div className="w-full h-64 mt-4 bg-nexus-800 rounded-md p-4 border border-nexus-600">
            <h4 className="text-xs font-mono text-nexus-400 mb-2">{artifact.name} Visualization</h4>
            <ResponsiveContainer width="100%" height="100%">
                <ChartComponent data={chartData.data}>
                    <CartesianGrid strokeDasharray="3 3" stroke="#27272a" />
                    <XAxis dataKey={xKey} stroke="#71717a" fontSize={10} />
                    <YAxis stroke="#71717a" fontSize={10} />
                    <Tooltip 
                        contentStyle={{ backgroundColor: '#18181b', borderColor: '#27272a', fontSize: '12px' }} 
                        itemStyle={{ color: '#e4e4e7' }}
                    />
                    <Legend />
                    {dataKeys.map((key, i) => (
                         // @ts-ignore
                        <DataComponent 
                            key={key} 
                            type="monotone" 
                            dataKey={key} 
                            stroke={`hsl(${i * 60 + 200}, 70%, 50%)`} 
                            fill={`hsl(${i * 60 + 200}, 70%, 50%)`} 
                            strokeWidth={2}
                            dot={false}
                        />
                    ))}
                </ChartComponent>
            </ResponsiveContainer>
        </div>
    );
};

import React, { useState, useEffect, useRef } from 'react';
import { 
  Bot, 
  Cpu, 
  Zap, 
  Send, 
  Paperclip, 
  Mic, 
  Image as ImageIcon, 
  FileText, 
  Trash2, 
  Plus,
  Loader2,
  Database
} from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import { Prism as SyntaxHighlighter } from 'react-syntax-highlighter';
import { vscDarkPlus } from 'react-syntax-highlighter/dist/esm/styles/prism';

import { Artifact, Message, ReasoningMode } from './types';
import * as DBService from './services/db';
import * as GeminiService from './services/gemini';
import { ChartRenderer } from './components/ChartRenderer';

function App() {
  const [messages, setMessages] = useState<Message[]>([]);
  const [artifacts, setArtifacts] = useState<Artifact[]>([]);
  const [inputText, setInputText] = useState('');
  const [mode, setMode] = useState<ReasoningMode>('flash');
  const [isProcessing, setIsProcessing] = useState(false);
  const [isRecording, setIsRecording] = useState(false);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    // Load initial state
    loadArtifacts();
    // Default welcome message
    setMessages([{
      id: 'init',
      role: 'model',
      text: "Nexus initialized. Research workspace active.\n\nI can assist with document analysis, data visualization, and complex reasoning. Upload files to the context sidebar to begin.",
      timestamp: Date.now()
    }]);
  }, []);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const loadArtifacts = async () => {
    const items = await DBService.getAllArtifacts();
    setArtifacts(items);
  };

  const handleSendMessage = async () => {
    if (!inputText.trim()) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: inputText,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInputText('');
    setIsProcessing(true);

    try {
      const responseText = await GeminiService.generateResponse(
        messages,
        artifacts,
        mode,
        userMsg.text
      );

      const botMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText,
        timestamp: Date.now(),
        isThinking: false
      };

      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
      console.error(error);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    for (let i = 0; i < files.length; i++) {
      const file = files[i];
      const reader = new FileReader();

      reader.onload = async (ev) => {
        const result = ev.target?.result as string;
        let type: Artifact['type'] = 'text';
        let content = result;

        if (file.type.startsWith('image/')) {
            type = 'image';
            // result is already base64 data url
            content = result.split(',')[1]; // Remove header
        } else if (file.type === 'text/csv' || file.name.endsWith('.csv')) {
            type = 'csv';
        } else if (file.type.startsWith('audio/')) {
            type = 'audio'; // Note: Not fully storing audio blob for now, just text usually, but for demo:
             // For audio upload, we probably want to transcribe immediately? 
             // Let's store it as an artifact first.
             content = result.split(',')[1];
        }

        const newArtifact: Artifact = {
          id: Date.now().toString() + Math.random().toString(),
          name: file.name,
          type,
          content,
          mimeType: file.type,
          createdAt: Date.now()
        };

        await DBService.saveArtifact(newArtifact);
        setArtifacts(prev => [...prev, newArtifact]);

        // If it's an image, let's optionally analyze it immediately? 
        // No, let user ask about it.
        // If it's audio, let's transcribe it immediately as a separate action or just let it sit?
        // Let's transcribe immediately if it's audio to make it searchable/usable.
        if (type === 'audio') {
           setIsProcessing(true);
           try {
             const transcription = await GeminiService.transcribeAudio(content, file.type);
             const transArtifact: Artifact = {
                id: Date.now().toString() + 'trans',
                name: `Transcript: ${file.name}`,
                type: 'text',
                content: transcription,
                createdAt: Date.now()
             };
             await DBService.saveArtifact(transArtifact);
             setArtifacts(prev => [...prev, transArtifact]);
           } catch(e) { console.error(e) }
           setIsProcessing(false);
        }
      };

      if (file.type.startsWith('image/') || file.type.startsWith('audio/')) {
        reader.readAsDataURL(file);
      } else {
        reader.readAsText(file);
      }
    }
    // clear input
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleDeleteArtifact = async (id: string) => {
    await DBService.deleteArtifact(id);
    setArtifacts(prev => prev.filter(a => a.id !== id));
  };

  const handleMicClick = async () => {
    if (isRecording) {
      // Stop recording logic handled by media recorder onstop
      // For simplicity in this React component, we'll toggle state and assuming native browser support
      // To implement robust recording, we'd need a MediaRecorder ref.
      return; 
    }

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      const chunks: Blob[] = [];

      mediaRecorder.ondataavailable = (e) => chunks.push(e.data);
      mediaRecorder.onstop = async () => {
        const blob = new Blob(chunks, { type: 'audio/webm' });
        const reader = new FileReader();
        reader.readAsDataURL(blob);
        reader.onloadend = async () => {
            const base64data = (reader.result as string).split(',')[1];
            setIsProcessing(true);
            try {
                // Transcribe
                const text = await GeminiService.transcribeAudio(base64data, 'audio/webm');
                setInputText(prev => prev + ' ' + text);
            } catch (e) {
                console.error("Mic error", e);
            } finally {
                setIsProcessing(false);
            }
        }
        setIsRecording(false);
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);

      // Auto stop after 5 seconds for this demo or wait for click?
      // Let's make the button a toggle.
      // We need a ref to the recorder to stop it.
      // For this simple implementation, let's just use a "Hold to record" or "Click to start/stop"
      // Improving logic:
      (window as any).currentRecorder = mediaRecorder;

    } catch (err) {
      console.error("Error accessing microphone:", err);
    }
  };

  const stopRecording = () => {
      if ((window as any).currentRecorder && isRecording) {
          (window as any).currentRecorder.stop();
      }
  }

  return (
    <div className="flex h-screen w-full bg-nexus-900 text-gray-200 font-sans overflow-hidden">

      {/* Sidebar: Context Memory */}
      <div className="w-80 border-r border-nexus-700 flex flex-col bg-nexus-800">
        <div className="p-4 border-b border-nexus-700 flex items-center justify-between">
            <h2 className="font-mono text-sm font-semibold tracking-wider text-nexus-accent flex items-center gap-2">
                <Database size={16} />
                CONTEXT MEMORY
            </h2>
            <button 
                onClick={() => fileInputRef.current?.click()}
                className="p-1.5 hover:bg-nexus-700 rounded transition-colors text-nexus-400 hover:text-white"
                title="Add to Context"
            >
                <Plus size={18} />
            </button>
            <input 
                type="file" 
                ref={fileInputRef} 
                className="hidden" 
                multiple 
                onChange={handleFileUpload}
            />
        </div>

        <div className="flex-1 overflow-y-auto p-3 space-y-2">
            {artifacts.length === 0 && (
                <div className="text-center mt-10 text-nexus-500 text-xs">
                    <p>No active context.</p>
                    <p className="mt-2">Upload files, images, or data to ground the agent's reasoning.</p>
                </div>
            )}
            {artifacts.map(art => (
                <div key={art.id} className="group relative bg-nexus-700/50 hover:bg-nexus-700 border border-nexus-600 rounded p-3 transition-all">
                    <div className="flex items-center gap-3 mb-2">
                        {art.type === 'text' && <FileText size={16} className="text-gray-400" />}
                        {art.type === 'image' && <ImageIcon size={16} className="text-purple-400" />}
                        {art.type === 'csv' && <Bot size={16} className="text-green-400" />} 
                        {art.type === 'audio' && <Mic size={16} className="text-red-400" />}
                        <span className="text-xs font-medium truncate flex-1" title={art.name}>{art.name}</span>
                        <button 
                            onClick={(e) => { e.stopPropagation(); handleDeleteArtifact(art.id); }}
                            className="text-nexus-500 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-opacity"
                        >
                            <Trash2 size={14} />
                        </button>
                    </div>
                    {art.type === 'image' && (
                        <div className="w-full h-24 bg-nexus-900 rounded overflow-hidden">
                             <img src={`data:${art.mimeType};base64,${art.content}`} className="w-full h-full object-cover opacity-70 group-hover:opacity-100 transition-opacity" />
                        </div>
                    )}
                    {art.type === 'text' && (
                         <p className="text-[10px] text-gray-500 line-clamp-3 font-mono">{art.content.substring(0, 100)}</p>
                    )}
                    {art.type === 'csv' && (
                         <div className="text-[10px] text-green-500/80 font-mono">Structured Data</div>
                    )}
                </div>
            ))}
        </div>
        <div className="p-3 border-t border-nexus-700 text-[10px] text-nexus-500 text-center">
            {artifacts.length} Active Artifacts
        </div>
      </div>

      {/* Main Area */}
      <div className="flex-1 flex flex-col min-w-0">

        {/* Header */}
        <div className="h-14 border-b border-nexus-700 flex items-center justify-between px-6 bg-nexus-900/90 backdrop-blur z-10">
            <h1 className="font-bold text-lg tracking-tight flex items-center gap-2">
                <span className="w-3 h-3 rounded-full bg-nexus-accent shadow-[0_0_10px_rgba(0,112,243,0.5)]"></span>
                NEXUS
            </h1>

            <div className="flex bg-nexus-800 p-1 rounded-lg border border-nexus-700">
                <button 
                    onClick={() => setMode('flash')}
                    className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-xs font-medium transition-all ${mode === 'flash' ? 'bg-nexus-600 text-white shadow-sm' : 'text-gray-400 hover:text-gray-200'}`}
                >
                    <Zap size={14} className={mode === 'flash' ? 'text-yellow-400' : ''} />
                    Flash
                </button>
                <button 
                    onClick={() => setMode('pro')}
                    className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-xs font-medium transition-all ${mode === 'pro' ? 'bg-nexus-600 text-white shadow-sm' : 'text-gray-400 hover:text-gray-200'}`}
                >
                    <Cpu size={14} className={mode === 'pro' ? 'text-blue-400' : ''} />
                    Pro Reasoning
                </button>
            </div>
        </div>

        {/* Chat Stream */}
        <div className="flex-1 overflow-y-auto p-6 space-y-6">
            {messages.map((msg, idx) => (
                <div key={msg.id} className={`flex gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}>
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 ${msg.role === 'model' ? 'bg-nexus-700 text-nexus-accent' : 'bg-gray-700 text-gray-300'}`}>
                        {msg.role === 'model' ? <Bot size={18} /> : <span className="text-xs font-bold">YOU</span>}
                    </div>

                    <div className={`max-w-3xl space-y-2 ${msg.role === 'user' ? 'items-end flex flex-col' : ''}`}>
                        <div className={`px-5 py-4 rounded-xl ${
                            msg.role === 'user' 
                                ? 'bg-nexus-600 text-white' 
                                : 'bg-transparent text-gray-300 border border-nexus-700'
                        }`}>
                            <ReactMarkdown
                                className="prose prose-invert prose-sm max-w-none"
                                components={{
                                    code({node, inline, className, children, ...props}: any) {
                                        const match = /language-(\w+)/.exec(className || '')
                                        return !inline && match ? (
                                        <SyntaxHighlighter
                                            style={vscDarkPlus}
                                            language={match[1]}
                                            PreTag="div"
                                            {...props}
                                        >
                                            {String(children).replace(/\n$/, '')}
                                        </SyntaxHighlighter>
                                        ) : (
                                        <code className={`${className} bg-nexus-800 px-1 py-0.5 rounded text-nexus-warning`} {...props}>
                                            {children}
                                        </code>
                                        )
                                    }
                                }}
                            >
                                {msg.text}
                            </ReactMarkdown>
                        </div>
                        {msg.role === 'model' && artifacts.filter(a => a.type === 'csv' && msg.text.toLowerCase().includes(a.name.toLowerCase())).map(a => (
                            <ChartRenderer key={a.id} artifact={a} />
                        ))}
                    </div>
                </div>
            ))}

            {isProcessing && (
                <div className="flex gap-4">
                     <div className="w-8 h-8 rounded-full bg-nexus-700 text-nexus-accent flex items-center justify-center shrink-0">
                        <Loader2 size={18} className="animate-spin" />
                    </div>
                    <div className="flex items-center gap-2 text-nexus-400 text-sm font-mono mt-1">
                        {mode === 'pro' ? 'Reasoning deeply...' : 'Processing...'}
                    </div>
                </div>
            )}
            <div ref={messagesEndRef} />
        </div>

        {/* Input Area */}
        <div className="p-4 border-t border-nexus-700 bg-nexus-800/50">
            <div className="max-w-4xl mx-auto flex gap-3 items-end">
                <div className="flex-1 bg-nexus-900 border border-nexus-600 rounded-xl flex items-center p-2 focus-within:border-nexus-accent transition-colors shadow-lg">
                    <button 
                        onClick={() => fileInputRef.current?.click()}
                        className="p-2 text-nexus-500 hover:text-nexus-200 transition-colors"
                        title="Upload Artifact"
                    >
                        <Paperclip size={20} />
                    </button>

                    <textarea 
                        value={inputText}
                        onChange={(e) => setInputText(e.target.value)}
                        onKeyDown={(e) => {
                            if (e.key === 'Enter' && !e.shiftKey) {
                                e.preventDefault();
                                handleSendMessage();
                            }
                        }}
                        placeholder="Ask Nexus..."
                        className="flex-1 bg-transparent border-none focus:ring-0 text-sm text-white placeholder-nexus-500 resize-none h-12 py-3 px-2"
                    />

                    <button 
                        onClick={isRecording ? stopRecording : handleMicClick}
                        className={`p-2 rounded-full transition-all ${isRecording ? 'bg-red-500/20 text-red-500 animate-pulse' : 'text-nexus-500 hover:text-nexus-200'}`}
                        title={isRecording ? "Stop Recording" : "Use Microphone"}
                    >
                        <Mic size={20} />
                    </button>
                </div>

                <button 
                    onClick={handleSendMessage}
                    disabled={!inputText.trim() || isProcessing}
