import React, { useState, useEffect, useRef } from 'react';
import { 
  Bot, 
  Cpu, 
  Zap, 
  Send, 
  Paperclip, 
  Mic, 
  Image as ImageIcon, 
  FileText, 
  Trash2, 
  Plus,
  Loader2,
  Database,
  Menu,
  X
} from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import { Prism as SyntaxHighlighter } from 'react-syntax-highlighter';
import { vscDarkPlus } from 'react-syntax-highlighter/dist/esm/styles/prism';

import { Artifact, Message, ReasoningMode } from './types';
import * as DBService from './services/db';
import * as GeminiService from './services/gemini';
import { ChartRenderer } from './components/ChartRenderer';

function App() {
  const [messages, setMessages] = useState<Message[]>([]);
  const [artifacts, setArtifacts] = useState<Artifact[]>([]);
  const [inputText, setInputText] = useState('');
  const [mode, setMode] = useState<ReasoningMode>('flash');
  const [isProcessing, setIsProcessing] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    // Load initial state
    loadArtifacts();
    // Default welcome message
    setMessages([{
      id: 'init',
      role: 'model',
      text: "Nexus initialized. Research workspace active.\n\nI can assist with document analysis, data visualization, and complex reasoning. Upload files to the context sidebar to begin.",
      timestamp: Date.now()
    }]);
  }, []);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const loadArtifacts = async () => {
    const items = await DBService.getAllArtifacts();
    setArtifacts(items);
  };

  const handleSendMessage = async () => {
    if (!inputText.trim()) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: inputText,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInputText('');
    setIsProcessing(true);

    try {
      const responseText = await GeminiService.generateResponse(
        messages,
        artifacts,
        mode,
        userMsg.text
      );

      const botMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText,
        timestamp: Date.now(),
        isThinking: false
      };

      setMessages(prev => [...prev, botMsg]);
    } catch (error) {
      console.error(error);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    // Close sidebar on mobile after selection if needed, but keeping it open might be better for bulk
    // setIsSidebarOpen(false);

    for (let i = 0; i < files.length; i++) {
      const file = files[i];
      const reader = new FileReader();

      reader.onload = async (ev) => {
        const result = ev.target?.result as string;
        let type: Artifact['type'] = 'text';
        let content = result;

        if (file.type.startsWith('image/')) {
            type = 'image';
            // result is already base64 data url
            content = result.split(',')[1]; // Remove header
        } else if (file.type === 'text/csv' || file.name.endsWith('.csv')) {
            type = 'csv';
        } else if (file.type.startsWith('audio/')) {
            type = 'audio';
             content = result.split(',')[1];
        }

        const newArtifact: Artifact = {
          id: Date.now().toString() + Math.random().toString(),
          name: file.name,
          type,
          content,
          mimeType: file.type,
          createdAt: Date.now()
        };

        await DBService.saveArtifact(newArtifact);
        setArtifacts(prev => [...prev, newArtifact]);

        if (type === 'audio') {
           setIsProcessing(true);
           try {
             const transcription = await GeminiService.transcribeAudio(content, file.type);
             const transArtifact: Artifact = {
                id: Date.now().toString() + 'trans',
                name: `Transcript: ${file.name}`,
                type: 'text',
                content: transcription,
                createdAt: Date.now()
             };
             await DBService.saveArtifact(transArtifact);
             setArtifacts(prev => [...prev, transArtifact]);
           } catch(e) { console.error(e) }
           setIsProcessing(false);
        }
      };

      if (file.type.startsWith('image/') || file.type.startsWith('audio/')) {
        reader.readAsDataURL(file);
      } else {
        reader.readAsText(file);
      }
    }
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleDeleteArtifact = async (id: string) => {
    await DBService.deleteArtifact(id);
    setArtifacts(prev => prev.filter(a => a.id !== id));
  };

  const handleMicClick = async () => {
    if (isRecording) {
      return; 
    }

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      const chunks: Blob[] = [];

      mediaRecorder.ondataavailable = (e) => chunks.push(e.data);
      mediaRecorder.onstop = async () => {
        const blob = new Blob(chunks, { type: 'audio/webm' });
        const reader = new FileReader();
        reader.readAsDataURL(blob);
        reader.onloadend = async () => {
            const base64data = (reader.result as string).split(',')[1];
            setIsProcessing(true);
            try {
                const text = await GeminiService.transcribeAudio(base64data, 'audio/webm');
                setInputText(prev => prev + ' ' + text);
            } catch (e) {
                console.error("Mic error", e);
            } finally {
                setIsProcessing(false);
            }
        }
        setIsRecording(false);
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);
      (window as any).currentRecorder = mediaRecorder;

    } catch (err) {
      console.error("Error accessing microphone:", err);
    }
  };

  const stopRecording = () => {
      if ((window as any).currentRecorder && isRecording) {
          (window as any).currentRecorder.stop();
      }
  }

  return (
    <div className="flex h-[100dvh] w-full bg-nexus-900 text-gray-200 font-sans overflow-hidden relative">

      {/* Mobile Overlay */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/60 z-40 md:hidden backdrop-blur-sm transition-opacity"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* Sidebar: Context Memory */}
      <div className={`
        fixed inset-y-0 left-0 z-50 w-80 bg-nexus-800 border-r border-nexus-700 flex flex-col transform transition-transform duration-300 ease-in-out
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} 
        md:relative md:translate-x-0
      `}>
        <div className="p-4 border-b border-nexus-700 flex items-center justify-between">
            <h2 className="font-mono text-sm font-semibold tracking-wider text-nexus-accent flex items-center gap-2">
                <Database size={16} />
                CONTEXT MEMORY
            </h2>
            <div className="flex items-center gap-1">
              <button 
                  onClick={() => fileInputRef.current?.click()}
                  className="p-2 hover:bg-nexus-700 rounded transition-colors text-nexus-400 hover:text-white touch-manipulation"
                  title="Add to Context"
              >
                  <Plus size={20} />
              </button>
              {/* Mobile Close Button */}
              <button 
                  onClick={() => setIsSidebarOpen(false)}
                  className="md:hidden p-2 hover:bg-nexus-700 rounded transition-colors text-gray-400 hover:text-white"
              >
                  <X size={20} />
              </button>
            </div>
            <input 
                type="file" 
                ref={fileInputRef} 
                className="hidden" 
                multiple 
                onChange={handleFileUpload}
            />
        </div>

        <div className="flex-1 overflow-y-auto p-3 space-y-2">
            {artifacts.length === 0 && (
                <div className="text-center mt-10 text-nexus-500 text-xs px-4">
                    <p>No active context.</p>
                    <p className="mt-2">Upload files, images, or data to ground the agent's reasoning.</p>
                </div>
            )}
            {artifacts.map(art => (
                <div key={art.id} className="group relative bg-nexus-700/50 hover:bg-nexus-700 border border-nexus-600 rounded p-3 transition-all touch-manipulation">
                    <div className="flex items-center gap-3 mb-2">
                        {art.type === 'text' && <FileText size={16} className="text-gray-400" />}
                        {art.type === 'image' && <ImageIcon size={16} className="text-purple-400" />}
                        {art.type === 'csv' && <Bot size={16} className="text-green-400" />} 
                        {art.type === 'audio' && <Mic size={16} className="text-red-400" />}
                        <span className="text-xs font-medium truncate flex-1" title={art.name}>{art.name}</span>
                        <button 
                            onClick={(e) => { e.stopPropagation(); handleDeleteArtifact(art.id); }}
                            className="text-nexus-500 hover:text-red-400 p-1 md:opacity-0 md:group-hover:opacity-100 transition-opacity"
                        >
                            <Trash2 size={16} />
                        </button>
                    </div>
                    {art.type === 'image' && (
                        <div className="w-full h-24 bg-nexus-900 rounded overflow-hidden">
                             <img src={`data:${art.mimeType};base64,${art.content}`} className="w-full h-full object-cover opacity-70 group-hover:opacity-100 transition-opacity" />
                        </div>
                    )}
                    {art.type === 'text' && (
                         <p className="text-[10px] text-gray-500 line-clamp-3 font-mono">{art.content.substring(0, 100)}</p>
                    )}
                    {art.type === 'csv' && (
                         <div className="text-[10px] text-green-500/80 font-mono">Structured Data</div>
                    )}
                </div>
            ))}
        </div>
        <div className="p-3 border-t border-nexus-700 text-[10px] text-nexus-500 text-center safe-area-bottom">
            {artifacts.length} Active Artifacts
        </div>
      </div>

      {/* Main Area */}
      <div className="flex-1 flex flex-col min-w-0 w-full">

        {/* Header */}
        <div className="h-14 border-b border-nexus-700 flex items-center justify-between px-4 md:px-6 bg-nexus-900/90 backdrop-blur z-30">
            <div className="flex items-center gap-3">
              <button 
                className="md:hidden text-gray-400 hover:text-white p-1"
                onClick={() => setIsSidebarOpen(true)}
              >
                <Menu size={24} />
              </button>
              <h1 className="font-bold text-lg tracking-tight flex items-center gap-2">
                  <span className="w-3 h-3 rounded-full bg-nexus-accent shadow-[0_0_10px_rgba(0,112,243,0.5)]"></span>
                  NEXUS
              </h1>
            </div>

            <div className="flex bg-nexus-800 p-1 rounded-lg border border-nexus-700">
                <button 
                    onClick={() => setMode('flash')}
