        fixed inset-y-0 left-0 z-50 w-80 bg-nexus-800 border-r border-nexus-700 flex flex-col transform transition-transform duration-300 ease-in-out
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} 
