                <button 
                    onClick={() => setMode('pro')}
                    className={`flex items-center gap-2 px-3 py-1.5 rounded-md text-xs font-medium transition-all ${mode === 'pro' ? 'bg-nexus-600 text-white shadow-sm' : 'text-gray-400 hover:text-gray-200'}`}
                >
                    <Cpu size={14} className={mode === 'pro' ? 'text-blue-400' : ''} />
                    <span className="hidden sm:inline">Pro Reasoning</span>
                    <span className="sm:hidden">Pro</span>
                </button>
            </div>
        </div>

        {/* Chat Stream */}
        <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-6">
            {messages.map((msg, idx) => (
                <div key={msg.id} className={`flex gap-3 md:gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}>
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 ${msg.role === 'model' ? 'bg-nexus-700 text-nexus-accent' : 'bg-gray-700 text-gray-300'}`}>
                        {msg.role === 'model' ? <Bot size={18} /> : <span className="text-[10px] font-bold">YOU</span>}
                    </div>

                    <div className={`max-w-[85%] md:max-w-3xl space-y-2 ${msg.role === 'user' ? 'items-end flex flex-col' : ''}`}>
                        <div className={`px-4 py-3 md:px-5 md:py-4 rounded-xl text-sm md:text-base ${
                            msg.role === 'user' 
                                ? 'bg-nexus-600 text-white' 
                                : 'bg-transparent text-gray-300 border border-nexus-700'
                        }`}>
                            <ReactMarkdown
                                className="prose prose-invert prose-sm max-w-none break-words"
                                components={{
                                    code({node, inline, className, children, ...props}: any) {
                                        const match = /language-(\w+)/.exec(className || '')
                                        return !inline && match ? (
                                        <div className="overflow-x-auto my-2 rounded-md">
                                            <SyntaxHighlighter
                                                style={vscDarkPlus}
                                                language={match[1]}
                                                PreTag="div"
                                                {...props}
                                                customStyle={{ margin: 0, fontSize: '0.85rem' }}
                                            >
                                                {String(children).replace(/\n$/, '')}
                                            </SyntaxHighlighter>
                                        </div>
                                        ) : (
                                        <code className={`${className} bg-nexus-800 px-1 py-0.5 rounded text-nexus-warning text-xs`} {...props}>
                                            {children}
                                        </code>
                                        )
                                    }
                                }}
                            >
                                {msg.text}
                            </ReactMarkdown>
                        </div>
                        {msg.role === 'model' && artifacts.filter(a => a.type === 'csv' && msg.text.toLowerCase().includes(a.name.toLowerCase())).map(a => (
                            <ChartRenderer key={a.id} artifact={a} />
                        ))}
                    </div>
                </div>
            ))}

            {isProcessing && (
                <div className="flex gap-4">
                     <div className="w-8 h-8 rounded-full bg-nexus-700 text-nexus-accent flex items-center justify-center shrink-0">
                        <Loader2 size={18} className="animate-spin" />
                    </div>
                    <div className="flex items-center gap-2 text-nexus-400 text-sm font-mono mt-1">
                        {mode === 'pro' ? 'Reasoning deeply...' : 'Processing...'}
                    </div>
                </div>
            )}
            <div ref={messagesEndRef} />
        </div>

        {/* Input Area */}
        <div className="p-3 md:p-4 border-t border-nexus-700 bg-nexus-800/90 backdrop-blur-sm safe-area-bottom">
            <div className="max-w-4xl mx-auto flex gap-2 md:gap-3 items-end">
                <div className="flex-1 bg-nexus-900 border border-nexus-600 rounded-xl flex items-center p-1.5 focus-within:border-nexus-accent transition-colors shadow-lg">
                    <button 
                        onClick={() => fileInputRef.current?.click()}
                        className="p-2 text-nexus-500 hover:text-nexus-200 transition-colors touch-manipulation"
                        title="Upload Artifact"
                    >
                        <Paperclip size={20} />
                    </button>

                    <textarea 
                        value={inputText}
                        onChange={(e) => setInputText(e.target.value)}
                        onKeyDown={(e) => {
                            if (e.key === 'Enter' && !e.shiftKey) {
                                e.preventDefault();
                                handleSendMessage();
                            }
                        }}
                        placeholder="Ask Nexus..."
                        className="flex-1 bg-transparent border-none focus:ring-0 text-sm md:text-base text-white placeholder-nexus-500 resize-none h-12 py-3 px-2 leading-relaxed"
                        style={{ minHeight: '48px', maxHeight: '120px' }}
                    />

                    <button 
                        onClick={isRecording ? stopRecording : handleMicClick}
                        className={`p-2 rounded-full transition-all touch-manipulation ${isRecording ? 'bg-red-500/20 text-red-500 animate-pulse' : 'text-nexus-500 hover:text-nexus-200'}`}
                        title={isRecording ? "Stop Recording" : "Use Microphone"}
                    >
                        <Mic size={20} />
                    </button>
                </div>

                <button 
                    onClick={handleSendMessage}
                    disabled={!inputText.trim() || isProcessing}
                    className="p-3 md:p-4 bg-nexus-accent hover:bg-blue-600 disabled:opacity-50 disabled:cursor-not-allowed text-white rounded-xl shadow-lg transition-all touch-manipulation shrink-0"
                >
                    <Send size={20} />
                </button>
            </div>
            <div className="max-w-4xl mx-auto mt-2 text-center">
                 <p className="text-[10px] text-nexus-500">
                    {mode === 'pro' ? 'Gemini 3 Pro' : 'Gemini 3 Flash'} • {artifacts.length} artifacts
                 </p>
            </div>
        </div>

      </div>
    </div>
  );
}

