                    <span className="text-lg font-mono font-bold text-nexus-warning">{systemMetrics.ram}%</span>
                </div>
            </div>

            {/* Orchestrator Logs */}
            <div className="space-y-3">
                <h3 className="text-[10px] font-bold text-nexus-500 uppercase tracking-widest flex items-center gap-2">
                    <TerminalIcon size={12} />
                    AUDIT LOGS
                </h3>
                <div className="p-3 rounded-xl bg-nexus-900 font-mono text-[10px] leading-relaxed space-y-2 text-nexus-500 border border-nexus-700 shadow-inner max-h-[400px] overflow-y-auto custom-scrollbar">
                    <p className="text-nexus-success">[SYSTEM] Initialization complete.</p>
                    <p className="text-nexus-accent">[POLICY] nexus_context_read_v1 loaded.</p>
                    <p>[AUTH] Agent message_process: AUTHORIZED</p>
                    <p>[SECURITY] Input validation scan: PASSED</p>
                    <p className="text-nexus-warning">[METRIC] Latency spike detected: 184ms</p>
                    <p>[OPA] Evaluation time: 14ms</p>
                    <p className="opacity-50">---------------------------------</p>
                    <p className="text-nexus-accent">[POLICY] Heartbeat active...</p>
                </div>
            </div>

            {/* Sandbox Isolation Status */}
            <div className="p-4 rounded-xl bg-nexus-accent/5 border border-nexus-accent/20 flex items-center gap-3">
                <div className="p-2 bg-nexus-accent/20 rounded-lg text-nexus-accent">
                    <HardDrive size={18} />
                </div>
                <div>
                    <h4 className="text-[11px] font-bold text-white uppercase tracking-tight">Virtual Sandbox</h4>
                    <p className="text-[10px] text-nexus-500 leading-tight">Environment is ephemeral and isolated from root system.</p>
                </div>
            </div>
        </div>

        <div className="p-4 border-t border-nexus-700 bg-nexus-900/40">
            <div className="flex justify-between items-center text-[9px] font-mono text-nexus-500">
                <span>INSTANCE_ID: NX-8842</span>
                <span className="text-nexus-success">HEALTHY</span>
            </div>
        </div>
      </div>

    </div>
  );
}

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { 
  Bot, 
  Cpu, 
  Zap, 
  Send, 
  Paperclip, 
  Mic, 
  Image as ImageIcon, 
  FileText, 
  Trash2, 
  Plus,
  Loader2,
  Database,
  Menu,
  X,
  Shield,
  ShieldCheck,
  ShieldAlert,
  Lock,
  Activity,
  Terminal as TerminalIcon,
  HardDrive,
  Globe,
  Settings,
  ChevronRight,
  Info,
  Layers,
  Sparkles,
  Command
} from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import { Prism as SyntaxHighlighter } from 'react-syntax-highlighter';
import { vscDarkPlus } from 'react-syntax-highlighter/dist/esm/styles/prism';

import { Artifact, Message, ReasoningMode } from './types';
import * as DBService from './services/db';
import * as GeminiService from './services/gemini';
import * as SecurityService from './services/security';
import * as Orchestrator from './services/orchestrator';
import { ChartRenderer } from './components/ChartRenderer';

function App() {
  const [messages, setMessages] = useState<Message[]>([]);
  const [artifacts, setArtifacts] = useState<Artifact[]>([]);
  const [inputText, setInputText] = useState('');
  const [mode, setMode] = useState<ReasoningMode>('flash');
  const [isProcessing, setIsProcessing] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isMonitorOpen, setIsMonitorOpen] = useState(false);
  const [securityStatus, setSecurityStatus] = useState<'idle' | 'scanning' | 'safe' | 'alert'>('idle');
  const [systemMetrics, setSystemMetrics] = useState({ cpu: 12, ram: 45, latency: 120, uptime: '00:00:00' });
  const [logs, setLogs] = useState<{ t: number, m: string, s: 'info'|'warn'|'error'|'sec' }[]>([]);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const startTime = useRef(Date.now());

  useEffect(() => {
    loadArtifacts();
    addLog('System kernel initialized', 'info');
    addLog('Loading encryption keys...', 'sec');

    const interval = setInterval(() => {
        const diff = Date.now() - startTime.current;
        const h = Math.floor(diff / 3600000).toString().padStart(2, '0');
        const m = Math.floor((diff % 3600000) / 60000).toString().padStart(2, '0');
        const s = Math.floor((diff % 60000) / 1000).toString().padStart(2, '0');

        setSystemMetrics(prev => ({
            cpu: Math.floor(Math.random() * 15) + 5,
            ram: 44 + (Math.sin(diff / 10000) * 2),
            latency: 105 + Math.floor(Math.random() * 40),
            uptime: `${h}:${m}:${s}`
        }));

        if (Math.random() > 0.8) {
            const events = ['Heartbeat pulse detected', 'IDB Sync active', 'Buffer optimization running', 'Socket handshake refreshed'];
            addLog(events[Math.floor(Math.random() * events.length)], 'info');
        }
    }, 1000);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const addLog = (m: string, s: 'info'|'warn'|'error'|'sec' = 'info') => {
      setLogs(prev => [{ t: Date.now(), m, s }, ...prev].slice(0, 50));
  };

  const loadArtifacts = async () => {
    const items = await DBService.getAllArtifacts();
    setArtifacts(items);
  };

  const handleSendMessage = async () => {
    if (!inputText.trim() || isProcessing) return;

    setSecurityStatus('scanning');
    addLog(`Scanning input for injection...`, 'sec');

    const securityCheck = await SecurityService.validateInput(inputText);

    if (securityCheck.status === 'MALICIOUS') {
        setSecurityStatus('alert');
        addLog(`THREAT DETECTED: ${securityCheck.reason}`, 'error');
        setMessages(prev => [...prev, {
            id: Date.now().toString(),
            role: 'model',
            text: `### 🔴 SECURITY BLOCK\n\n**Threat Identified**: \`PROMPT_INJECTION_V3\`\n**Risk Level**: CRITICAL\n\nNexus has intercepted an unauthorized control command within your input. System integrity maintained.`,
            timestamp: Date.now()
        }]);
        return;
    }

    addLog('Authorization verified. Processing...', 'info');
    setSecurityStatus('safe');
    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: inputText,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInputText('');
    setIsProcessing(true);

    try {
      const responseText = await GeminiService.generateResponse(
        messages,
        artifacts,
        mode,
        userMsg.text
      );

      const botMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText,
        timestamp: Date.now()
      };

      setMessages(prev => [...prev, botMsg]);
      addLog('Reasoning completed successfully', 'info');
    } catch (error: any) {
      addLog(`API error: ${error.message}`, 'error');
    } finally {
      setIsProcessing(false);
      setTimeout(() => setSecurityStatus('idle'), 3000);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    for (let i = 0; i < files.length; i++) {
      const file = files[i];
      addLog(`Ingesting artifact: ${file.name}`, 'info');
      const reader = new FileReader();

      reader.onload = async (ev) => {
        const result = ev.target?.result as string;
        let type: Artifact['type'] = 'text';
        let content = result;

        if (file.type.startsWith('image/')) {
            type = 'image';
            content = result.split(',')[1];
        } else if (file.type === 'text/csv' || file.name.endsWith('.csv')) {
            type = 'csv';
        } else if (file.type.startsWith('audio/')) {
            type = 'audio';
            content = result.split(',')[1];
        }

        const newArtifact: Artifact = {
          id: Date.now().toString() + Math.random().toString(),
          name: file.name,
          type,
          content,
          mimeType: file.type,
          createdAt: Date.now()
        };

        await DBService.saveArtifact(newArtifact);
        setArtifacts(prev => [...prev, newArtifact]);
        addLog(`Vault entry created: ${newArtifact.id.slice(0,8)}`, 'sec');
      };

      if (file.type.startsWith('image/') || file.type.startsWith('audio/')) {
        reader.readAsDataURL(file);
      } else {
        reader.readAsText(file);
      }
    }
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handlePurgeMemory = async () => {
    if (artifacts.length === 0) return;
    if (window.confirm("PURGE CORE MEMORY? All contextual artifacts will be permanently destroyed.")) {
        addLog('INITIATING CORE PURGE...', 'warn');
        await DBService.clearArtifacts();
        setArtifacts([]);
        addLog('Memory bank cleared.', 'info');
    }
  };

  return (
    <div className="flex h-[100dvh] w-full bg-nexus-950 text-gray-200 font-sans overflow-hidden relative">

      {/* Background Scan Line */}
      <div className="scan-line" />

      {/* LEFT SIDEBAR: Context Memory */}
      <div className={`fixed inset-y-0 left-0 z-50 w-72 glass border-r border-nexus-700/50 flex flex-col transform transition-transform duration-300 ease-in-out ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} md:relative md:translate-x-0 shadow-2xl shadow-black/50`}>
        <div className="p-5 border-b border-nexus-700/30 flex items-center justify-between">
            <div className="flex items-center gap-2">
                <Database size={16} className="text-nexus-accent" />
                <h2 className="font-mono text-[10px] font-bold tracking-[0.3em] text-nexus-500 uppercase">Memory Bank</h2>
            </div>
            <div className="flex items-center gap-2">
                <button onClick={handlePurgeMemory} className="p-1.5 hover:bg-nexus-error/10 text-nexus-500 hover:text-nexus-error rounded transition-all" title="Purge Context">
                    <Trash2 size={14} />
                </button>
                <button onClick={() => fileInputRef.current?.click()} className="p-1.5 bg-nexus-accent/10 hover:bg-nexus-accent/20 text-nexus-accent rounded transition-all">
                    <Plus size={16} />
                </button>
            </div>
            <input type="file" ref={fileInputRef} className="hidden" multiple onChange={handleFileUpload} />
        </div>

        <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar">
            {artifacts.length === 0 && (
                <div className="flex flex-col items-center justify-center h-40 opacity-30">
                    <Layers size={24} className="mb-2" />
                    <span className="text-[10px] font-mono uppercase tracking-widest">Awaiting Artifacts</span>
                </div>
            )}
            {artifacts.map(art => (
                <div key={art.id} className="group relative glass border border-nexus-700/30 rounded-lg p-3 transition-all hover:border-nexus-accent/40 hover:shadow-[0_0_10px_rgba(0,112,243,0.1)]">
                    <div className="flex items-center gap-2 mb-2">
                        <div className="w-1.5 h-1.5 rounded-full bg-nexus-success shadow-[0_0_5px_#10b981]" />
                        <span className="text-[11px] font-mono font-medium truncate flex-1 tracking-tight">{art.name}</span>
                        <ShieldCheck size={12} className="text-nexus-success opacity-50" />
                    </div>
                    <div className="flex justify-between items-center">
                        <span className="text-[9px] font-mono text-nexus-500 uppercase tracking-tighter">{art.type} // {new Date(art.createdAt).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</span>
                        <button onClick={() => DBService.deleteArtifact(art.id).then(loadArtifacts)} className="opacity-0 group-hover:opacity-100 p-1 hover:text-nexus-error transition-all">
                            <X size={12} />
                        </button>
                    </div>
                </div>
            ))}
        </div>
        <div className="p-4 border-t border-nexus-700/30">
             <div className="flex items-center justify-between text-[9px] font-mono text-nexus-500">
                <span>ENCRYPTION: AES-256</span>
                <span className="text-nexus-success">ACTIVE</span>
             </div>
        </div>
      </div>

      {/* MAIN WORKSPACE */}
      <div className="flex-1 flex flex-col min-w-0 w-full relative">

        {/* TOP STATUS BAR */}
        <div className="h-14 glass border-b border-nexus-700/30 flex items-center justify-between px-6 z-30">
            <div className="flex items-center gap-6">
              <button className="md:hidden text-gray-400" onClick={() => setIsSidebarOpen(!isSidebarOpen)}>
                <Menu size={18} />
              </button>
              <div className="flex items-center gap-3">
                  <div className="flex flex-col">
                      <h1 className="text-xs font-bold tracking-[0.4em] font-mono flex items-center gap-2">
                        <Sparkles size={14} className="text-nexus-accent animate-pulse" />
                        NEXUS
                      </h1>
                      <div className="flex items-center gap-1.5 mt-0.5">
                        <div className="w-1.5 h-1.5 rounded-full bg-nexus-success shadow-[0_0_8px_#10b981]" />
                        <span className="text-[8px] font-mono text-nexus-500 uppercase tracking-widest">Kernel v3.1.2 Ready</span>
                      </div>
                  </div>
              </div>
            </div>

            <div className="flex items-center gap-4">
                <div className="hidden lg:flex items-center gap-6 mr-6 text-[9px] font-mono font-bold tracking-tighter">
                    <div className="flex flex-col items-end">
                        <span className="text-nexus-500 text-[8px] uppercase">Latency</span>
                        <span className="text-nexus-accent">{systemMetrics.latency}ms</span>
                    </div>
                    <div className="flex flex-col items-end">
                        <span className="text-nexus-500 text-[8px] uppercase">Uptime</span>
                        <span className="text-gray-300">{systemMetrics.uptime}</span>
                    </div>
                </div>

                <div className="flex bg-nexus-900 border border-nexus-700/50 p-1 rounded-lg">
                    <button onClick={() => setMode('flash')} className={`flex items-center gap-2 px-3 py-1 rounded text-[10px] font-bold uppercase transition-all ${mode === 'flash' ? 'bg-nexus-accent/20 text-nexus-accent border border-nexus-accent/30' : 'text-nexus-500 hover:text-gray-300 border border-transparent'}`}>
                        <Zap size={10} /> Flash
                    </button>
                    <button onClick={() => setMode('pro')} className={`flex items-center gap-2 px-3 py-1 rounded text-[10px] font-bold uppercase transition-all ${mode === 'pro' ? 'bg-nexus-accent/20 text-nexus-accent border border-nexus-accent/30' : 'text-nexus-500 hover:text-gray-300 border border-transparent'}`}>
                        <Cpu size={10} /> Pro
                    </button>
                </div>

                <button onClick={() => setIsMonitorOpen(!isMonitorOpen)} className={`p-2 rounded-lg transition-all border ${isMonitorOpen ? 'border-nexus-accent/50 text-nexus-accent bg-nexus-accent/5 shadow-[0_0_10px_rgba(0,112,243,0.1)]' : 'border-nexus-700/50 text-nexus-500 hover:text-white hover:bg-nexus-700/50'}`}>
                    <Activity size={18} />
                </button>
            </div>
        </div>

        {/* DIALOG STREAM */}
        <div className="flex-1 overflow-y-auto p-4 md:p-10 space-y-10 custom-scrollbar">
            {messages.length === 0 && (
                <div className="flex flex-col items-center justify-center min-h-[60vh] text-center animate-in fade-in zoom-in duration-700">
                    <div className="w-20 h-20 bg-nexus-accent/5 rounded-full flex items-center justify-center mb-6 relative">
                        <Bot size={40} className="text-nexus-accent animate-pulse-slow" />
                        <div className="absolute inset-0 border border-nexus-accent/20 rounded-full animate-ping opacity-20" />
                    </div>
                    <h3 className="text-xl font-mono font-bold tracking-[0.2em] mb-2 uppercase">Nexus Interface</h3>
                    <p className="text-nexus-500 text-sm max-w-sm leading-relaxed font-mono italic">
                        "Grounding intelligence in secure multimodal context."
                    </p>
                    <div className="mt-8 flex gap-3">
                        <div className="px-4 py-1.5 glass border border-nexus-700/50 rounded-full text-[10px] font-mono text-nexus-accent flex items-center gap-2">
                             <Command size={12} /> CMD-SCAN ACTIVE
                        </div>
                    </div>
                </div>
            )}

            {messages.map((msg) => (
                <div key={msg.id} className={`flex gap-6 ${msg.role === 'user' ? 'flex-row-reverse' : ''} animate-in slide-in-from-bottom-2 duration-500`}>
                    <div className={`w-10 h-10 rounded-xl flex items-center justify-center shrink-0 border border-nexus-700/50 shadow-lg ${msg.role === 'model' ? 'bg-nexus-900 text-nexus-accent' : 'bg-nexus-800 text-gray-300'}`}>
                        {msg.role === 'model' ? <Bot size={22} /> : <div className="text-[10px] font-mono font-bold tracking-tighter">USR</div>}
                    </div>
                    <div className={`max-w-[85%] md:max-w-4xl space-y-3 ${msg.role === 'user' ? 'items-end' : ''}`}>
                        <div className={`px-6 py-5 rounded-2xl text-[15px] leading-relaxed shadow-xl border ${msg.role === 'user' ? 'bg-nexus-accent text-white border-nexus-accent shadow-nexus-accent/10 message-frame-user' : 'glass border-nexus-700/40 text-gray-200 message-frame-model'}`}>
                            <ReactMarkdown className="prose prose-invert prose-sm max-w-none prose-p:my-2" components={{
                                code({node, inline, className, children, ...props}: any) {
                                    const match = /language-(\w+)/.exec(className || '')
                                    return !inline && match ? (
                                        <div className="relative group my-6">
                                            <div className="absolute top-2 right-2 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                                <span className="text-[9px] font-mono bg-nexus-900/80 px-2 py-1 rounded border border-nexus-700 text-nexus-500 uppercase">{match[1]}</span>
                                                <button className="p-1 hover:text-white transition-colors"><TerminalIcon size={12} /></button>
                                            </div>
                                            <div className="rounded-xl overflow-hidden border border-nexus-700/50 shadow-2xl">
                                                <SyntaxHighlighter style={vscDarkPlus} language={match[1]} PreTag="div" {...props} customStyle={{ margin: 0, padding: '1.5rem', fontSize: '0.85rem', background: 'rgba(5,5,5,0.8)' }}>
                                                    {String(children).replace(/\n$/, '')}
                                                </SyntaxHighlighter>
                                            </div>
                                        </div>
                                    ) : (
                                        <code className="bg-white/10 px-1.5 py-0.5 rounded text-nexus-warning font-mono text-[13px]" {...props}>
                                            {children}
                                        </code>
                                    )
                                }
                            }}>
                                {msg.text}
                            </ReactMarkdown>
                        </div>
                        {msg.role === 'model' && artifacts.filter(a => a.type === 'csv' && msg.text.toLowerCase().includes(a.name.toLowerCase())).map(a => (
                            <div key={a.id} className="w-full animate-in zoom-in duration-500">
                                <ChartRenderer artifact={a} />
                            </div>
                        ))}
                    </div>
                </div>
            ))}
            {isProcessing && (
                <div className="flex gap-6 animate-pulse">
                     <div className="w-10 h-10 rounded-xl bg-nexus-900 border border-nexus-700 flex items-center justify-center">
                        <Loader2 size={22} className="animate-spin text-nexus-accent" />
                    </div>
                    <div className="flex flex-col gap-2 py-1">
                        <div className="flex items-center gap-2 text-[10px] font-mono text-nexus-success uppercase tracking-widest font-bold">
                            <ShieldCheck size={14} /> Security Passed
                        </div>
                        <div className="text-[12px] font-mono text-nexus-500 uppercase tracking-[0.25em] flex items-center gap-2">
                            {mode === 'pro' ? 'Analyzing multi-step logic' : 'Generating synthesis'}
                            <span className="flex gap-1"><span className="w-1 h-1 bg-nexus-500 rounded-full animate-bounce" /><span className="w-1 h-1 bg-nexus-500 rounded-full animate-bounce [animation-delay:0.2s]" /><span className="w-1 h-1 bg-nexus-500 rounded-full animate-bounce [animation-delay:0.4s]" /></span>
                        </div>
                    </div>
                </div>
            )}
            <div ref={messagesEndRef} />
        </div>

        {/* MISSION CONTROL INPUT */}
        <div className="p-6 glass border-t border-nexus-700/30 safe-area-bottom">
            <div className="max-w-5xl mx-auto relative">
                <div className={`relative bg-nexus-950 border transition-all duration-500 rounded-2xl shadow-2xl overflow-hidden ${securityStatus === 'alert' ? 'border-nexus-error ring-4 ring-nexus-error/10' : 'border-nexus-700/50 focus-within:border-nexus-accent/50 focus-within:ring-4 focus-within:ring-nexus-accent/5'}`}>

                    {/* Dynamic Scanner Bar */}
                    {securityStatus === 'scanning' && (
                        <div className="absolute top-0 left-0 h-[2px] bg-nexus-accent animate-progress w-full z-10 shadow-[0_0_10px_#0070f3]" />
                    )}

                    <div className="flex items-end p-2.5 gap-2">
                        <div className="flex flex-col gap-1 pb-1">
                             <button onClick={() => fileInputRef.current?.click()} className="p-3 text-nexus-500 hover:text-nexus-accent transition-all rounded-xl hover:bg-nexus-accent/5">
                                <Paperclip size={20} />
                            </button>
                        </div>

                        <textarea 
                            value={inputText} 
                            onChange={(e) => setInputText(e.target.value)} 
                            onKeyDown={(e) => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSendMessage(); } }} 
                            placeholder="Ground a query in context..." 
                            className="flex-1 bg-transparent border-none focus:ring-0 text-[15px] py-4 px-2 min-h-[60px] max-h-[200px] resize-none font-sans text-gray-100 placeholder-nexus-600 leading-relaxed"
                        />

                        <div className="flex items-center gap-3 pr-2 pb-2">
                             <div className={`flex items-center gap-2 px-3 py-2 rounded-xl bg-nexus-900/80 border transition-all ${securityStatus === 'alert' ? 'border-nexus-error/50 bg-nexus-error/5' : 'border-nexus-700/50 shadow-inner'}`}>
                                {securityStatus === 'scanning' && <Loader2 size={16} className="animate-spin text-nexus-accent" />}
                                {securityStatus === 'safe' && <ShieldCheck size={16} className="text-nexus-success" />}
                                {securityStatus === 'alert' && <ShieldAlert size={16} className="text-nexus-error" />}
                                {securityStatus === 'idle' && <Shield size={16} className="text-nexus-500" />}
                                <span className={`text-[10px] font-mono uppercase font-bold hidden sm:inline ${securityStatus === 'alert' ? 'text-nexus-error' : 'text-nexus-500'}`}>
                                    {securityStatus === 'scanning' ? 'VALIDATING' : securityStatus === 'alert' ? 'BLOCKED' : 'SECURE'}
                                </span>
                             </div>

                             <button onClick={handleSendMessage} disabled={!inputText.trim() || isProcessing} className="p-4 bg-nexus-accent hover:bg-blue-600 disabled:opacity-20 disabled:grayscale text-white rounded-xl shadow-lg transition-all transform active:scale-95 shadow-nexus-accent/20">
                                <Send size={20} />
                            </button>
                        </div>
                    </div>
                </div>

                <div className="mt-3 flex justify-between items-center px-4">
                    <div className="flex items-center gap-6">
                        <div className="flex items-center gap-1.5 text-[10px] font-mono text-nexus-500 uppercase tracking-widest font-bold">
                            <Lock size={12} className="text-nexus-success" /> TLSv1.3_AES256
                        </div>
                        <div className="hidden sm:flex items-center gap-1.5 text-[10px] font-mono text-nexus-500 uppercase tracking-widest font-bold">
                            <Globe size={12} /> EDGE_SECURE: ON
                        </div>
                    </div>
                    <div className="text-[9px] font-mono text-nexus-600 uppercase tracking-[0.3em]">
                        Nexus-Build-3.1.2_Stable
                    </div>
                </div>
            </div>
        </div>
      </div>

