                    <div className="w-full h-1 bg-nexus-900 rounded-full mt-2 overflow-hidden">
                        <div className="h-full bg-nexus-accent transition-all duration-500" style={{ width: `${systemMetrics.cpu}%` }} />
                    </div>
                </div>
                <div className="p-4 rounded-xl glass border border-nexus-700/50 flex flex-col gap-1 shadow-inner">
                    <span className="text-[9px] font-bold text-nexus-500 uppercase tracking-widest">VRAM USED</span>
                    <span className="text-xl font-mono font-bold text-nexus-warning">{Math.floor(systemMetrics.ram)}%</span>
                    <div className="w-full h-1 bg-nexus-900 rounded-full mt-2 overflow-hidden">
                        <div className="h-full bg-nexus-warning transition-all duration-500" style={{ width: `${systemMetrics.ram}%` }} />
                    </div>
                </div>
            </div>

            {/* Audit Logs */}
            <div className="space-y-4">
                <div className="flex justify-between items-center">
                    <h3 className="text-[10px] font-bold text-nexus-500 uppercase tracking-widest flex items-center gap-2">
                        <TerminalIcon size={12} />
                        Audit Stream
                    </h3>
                    <button onClick={() => setLogs([])} className="text-[9px] font-mono text-nexus-accent hover:underline uppercase">Clear</button>
                </div>
                <div className="p-4 rounded-xl bg-nexus-950 font-mono text-[10px] leading-relaxed space-y-3 border border-nexus-700/50 shadow-inner h-[400px] overflow-y-auto custom-scrollbar">
                    {logs.map((log, i) => (
                        <div key={i} className="flex gap-2 border-l border-nexus-700 pl-3">
                            <span className="text-nexus-500 shrink-0">[{new Date(log.t).toLocaleTimeString([], {hour12:false, hour:'2-digit', minute:'2-digit', second:'2-digit'})}]</span>
                            <span className={`
                                ${log.s === 'sec' ? 'text-nexus-accent font-bold' : ''}
                                ${log.s === 'warn' ? 'text-nexus-warning' : ''}
                                ${log.s === 'error' ? 'text-nexus-error' : ''}
                                ${log.s === 'info' ? 'text-gray-400' : ''}
                            `}>
                                {log.s === 'sec' ? '🔒 ' : log.s === 'warn' ? '⚠️ ' : log.s === 'error' ? '🚫 ' : ''}
                                {log.m}
                            </span>
                        </div>
                    ))}
                </div>
            </div>

            {/* Sandbox Visualizer */}
            <div className="p-5 rounded-2xl glass border border-nexus-accent/20 bg-nexus-accent/5 shadow-[0_0_20px_rgba(0,112,243,0.05)]">
                <div className="flex items-center gap-3 mb-3">
                    <div className="p-2.5 bg-nexus-accent/20 rounded-xl text-nexus-accent shadow-lg">
                        <HardDrive size={20} />
                    </div>
                    <div>
                        <h4 className="text-[11px] font-bold text-white uppercase tracking-tight">Isolated Sandbox</h4>
                        <p className="text-[9px] text-nexus-accent font-mono">STATUS: ENFORCED</p>
                    </div>
                </div>
                <p className="text-[10px] text-nexus-500 leading-relaxed font-medium">
                    Session state is strictly encapsulated. All file reads are monitored by OPA policy engine.
                </p>
            </div>
        </div>

        <div className="p-5 border-t border-nexus-700/30 glass">
            <div className="flex justify-between items-center text-[10px] font-mono">
                <span className="text-nexus-500 tracking-tighter">NODE_ID: NEXUS-NY-772</span>
                <div className="flex items-center gap-1.5">
                    <span className="w-1.5 h-1.5 rounded-full bg-nexus-success animate-pulse" />
                    <span className="text-nexus-success font-bold">ONLINE</span>
                </div>
            </div>
        </div>
      </div>

    </div>
  );
}

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { 
  Bot, 
  Cpu, 
  Zap, 
  Send, 
  Paperclip, 
  Mic, 
  Image as ImageIcon, 
  FileText, 
  Trash2, 
  Plus,
  Loader2,
  Database,
  Menu,
  X,
  Shield,
  ShieldCheck,
  ShieldAlert,
  Lock,
  Activity,
  Terminal as TerminalIcon,
  HardDrive,
  Globe,
  Sparkles,
  Command,
  Layout
} from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import { Prism as SyntaxHighlighter } from 'react-syntax-highlighter';
import { vscDarkPlus } from 'react-syntax-highlighter/dist/esm/styles/prism';

import { Artifact, Message, ReasoningMode } from './types';
import * as DBService from './services/db';
import * as GeminiService from './services/gemini';
import * as SecurityService from './services/security';
import * as Orchestrator from './services/orchestrator';
import { ChartRenderer } from './components/ChartRenderer';

function App() {
  const [messages, setMessages] = useState<Message[]>([]);
  const [artifacts, setArtifacts] = useState<Artifact[]>([]);
  const [inputText, setInputText] = useState('');
  const [mode, setMode] = useState<ReasoningMode>('flash');
  const [isProcessing, setIsProcessing] = useState(false);
  const [isRecording, setIsRecording] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isMonitorOpen, setIsMonitorOpen] = useState(false);
  const [securityStatus, setSecurityStatus] = useState<'idle' | 'scanning' | 'safe' | 'alert'>('idle');
  const [systemMetrics, setSystemMetrics] = useState({ cpu: 12, ram: 45, latency: 120, uptime: '00:00:00' });
  const [logs, setLogs] = useState<{ t: number, m: string, s: 'info'|'warn'|'error'|'sec' }[]>([]);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const startTime = useRef(Date.now());

  useEffect(() => {
    loadArtifacts();
    addLog('System kernel initialized', 'info');
    addLog('Enforcing OPA policies...', 'sec');

    const interval = setInterval(() => {
        const diff = Date.now() - startTime.current;
        const h = Math.floor(diff / 3600000).toString().padStart(2, '0');
        const m = Math.floor((diff % 3600000) / 60000).toString().padStart(2, '0');
        const s = Math.floor((diff % 60000) / 1000).toString().padStart(2, '0');

        setSystemMetrics(prev => ({
            cpu: Math.floor(Math.random() * 15) + 5,
            ram: 44 + (Math.sin(diff / 10000) * 2),
            latency: 105 + Math.floor(Math.random() * 40),
            uptime: `${h}:${m}:${s}`
        }));

        if (Math.random() > 0.85) {
            const events = ['Telemetry heartbeat stable', 'Encryption rotation complete', 'IDB Sync verified', 'OPA engine response: 12ms'];
            addLog(events[Math.floor(Math.random() * events.length)], 'info');
        }
    }, 1000);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const addLog = (m: string, s: 'info'|'warn'|'error'|'sec' = 'info') => {
      setLogs(prev => [{ t: Date.now(), m, s }, ...prev].slice(0, 50));
  };

  const loadArtifacts = async () => {
    const items = await DBService.getAllArtifacts();
    setArtifacts(items);
  };

  const handleSendMessage = async () => {
    if (!inputText.trim() || isProcessing) return;

    setSecurityStatus('scanning');
    addLog(`Dual-LLM Scan initiated...`, 'sec');

    const securityCheck = await SecurityService.validateInput(inputText);

    if (securityCheck.status === 'MALICIOUS') {
        setSecurityStatus('alert');
        addLog(`MALICIOUS INPUT REJECTED: ${securityCheck.reason}`, 'error');
        setMessages(prev => [...prev, {
            id: Date.now().toString(),
            role: 'model',
            text: `### 🔴 SECURITY BLOCK\n\n**Pattern**: \`INDIRECT_INJECTION_DETECTED\`\n**Validator**: Security Core v2\n\nNexus has intercepted an unauthorized control sequence. System state remains locked.`,
            timestamp: Date.now()
        }]);
        return;
    }

    setSecurityStatus('safe');
    addLog('Validation success. Forwarding to engine...', 'info');
    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: inputText,
      timestamp: Date.now()
    };

    setMessages(prev => [...prev, userMsg]);
    setInputText('');
    setIsProcessing(true);

    try {
      const responseText = await GeminiService.generateResponse(
        messages,
        artifacts,
        mode,
        userMsg.text
      );

      const botMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText,
        timestamp: Date.now()
      };

      setMessages(prev => [...prev, botMsg]);
      addLog(`Engine response completed in ${mode} mode`, 'info');
    } catch (error: any) {
      addLog(`Orchestration failure: ${error.message}`, 'error');
    } finally {
      setIsProcessing(false);
      setTimeout(() => setSecurityStatus('idle'), 3000);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;

    for (let i = 0; i < files.length; i++) {
      const file = files[i];
      addLog(`Vetting artifact: ${file.name}`, 'info');
      const reader = new FileReader();

      reader.onload = async (ev) => {
        const result = ev.target?.result as string;
        let type: Artifact['type'] = 'text';
        let content = result;

        if (file.type.startsWith('image/')) {
            type = 'image';
            content = result.split(',')[1];
        } else if (file.type === 'text/csv' || file.name.endsWith('.csv')) {
            type = 'csv';
        } else if (file.type.startsWith('audio/')) {
            type = 'audio';
            content = result.split(',')[1];
        }

        const newArtifact: Artifact = {
          id: Date.now().toString() + Math.random().toString(),
          name: file.name,
          type,
          content,
          mimeType: file.type,
          createdAt: Date.now()
        };

        await DBService.saveArtifact(newArtifact);
        setArtifacts(prev => [...prev, newArtifact]);
        addLog(`Vault storage committed: ${newArtifact.name}`, 'sec');
      };

      if (file.type.startsWith('image/') || file.type.startsWith('audio/')) {
        reader.readAsDataURL(file);
      } else {
        reader.readAsText(file);
      }
    }
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handlePurgeMemory = async () => {
    if (artifacts.length === 0) return;
    if (window.confirm("CONFIRM SYSTEM PURGE? All artifacts in memory will be deleted.")) {
        addLog('PURGING MEMORY VAULT...', 'warn');
        await DBService.clearArtifacts();
        setArtifacts([]);
        addLog('Purge complete.', 'info');
    }
  };

  return (
    <div className="flex h-[100dvh] w-full bg-nexus-950 text-gray-200 font-sans overflow-hidden relative">

      <div className="scan-line" />

      {/* MOBILE OVERLAYS */}
      {(isSidebarOpen || (isMonitorOpen && window.innerWidth < 1024)) && (
        <div 
            className="fixed inset-0 bg-black/70 backdrop-blur-sm z-40 transition-opacity lg:hidden"
            onClick={() => { setIsSidebarOpen(false); setIsMonitorOpen(false); }}
        />
      )}

      {/* LEFT SIDEBAR: Context Memory */}
      <div className={`
        fixed inset-y-0 left-0 z-50 w-[85%] sm:w-72 glass border-r border-nexus-700/50 flex flex-col transform transition-transform duration-300 ease-in-out
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} 
        md:relative md:translate-x-0 md:z-auto
      `}>
        <div className="p-4 sm:p-5 border-b border-nexus-700/30 flex items-center justify-between bg-nexus-900/40">
            <div className="flex items-center gap-2">
                <Database size={16} className="text-nexus-accent" />
                <h2 className="font-mono text-[10px] font-bold tracking-[0.3em] text-nexus-500 uppercase">Memory Bank</h2>
            </div>
            <div className="flex items-center gap-2">
                <button onClick={handlePurgeMemory} className="p-2 hover:bg-nexus-error/10 text-nexus-500 hover:text-nexus-error rounded-lg transition-all">
                    <Trash2 size={16} />
                </button>
                <button onClick={() => fileInputRef.current?.click()} className="p-2 bg-nexus-accent/10 hover:bg-nexus-accent/20 text-nexus-accent rounded-lg transition-all">
                    <Plus size={18} />
                </button>
                <button onClick={() => setIsSidebarOpen(false)} className="md:hidden p-2 text-nexus-500">
                    <X size={20} />
                </button>
            </div>
            <input type="file" ref={fileInputRef} className="hidden" multiple onChange={handleFileUpload} />
        </div>

        <div className="flex-1 overflow-y-auto p-3 sm:p-4 space-y-3 custom-scrollbar">
            {artifacts.length === 0 && (
                <div className="flex flex-col items-center justify-center h-40 opacity-20">
                    <Layout size={24} className="mb-2" />
                    <span className="text-[10px] font-mono uppercase tracking-widest text-center">Context Depleted</span>
                </div>
            )}
            {artifacts.map(art => (
                <div key={art.id} className="group relative glass border border-nexus-700/30 rounded-xl p-3 transition-all hover:border-nexus-accent/40 active:scale-[0.98]">
                    <div className="flex items-center gap-2 mb-2">
                        <div className="w-1.5 h-1.5 rounded-full bg-nexus-success shadow-[0_0_5px_#10b981] shrink-0" />
                        <span className="text-[11px] font-mono font-medium truncate flex-1 tracking-tight">{art.name}</span>
                        <ShieldCheck size={12} className="text-nexus-success opacity-50 shrink-0" />
                    </div>
                    <div className="flex justify-between items-center text-[9px] font-mono text-nexus-500 uppercase">
                        <span>{art.type} // {new Date(art.createdAt).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</span>
                        <button onClick={() => DBService.deleteArtifact(art.id).then(loadArtifacts)} className="p-1 hover:text-nexus-error">
                            <X size={12} />
                        </button>
                    </div>
                </div>
            ))}
        </div>
        <div className="p-4 border-t border-nexus-700/30 bg-nexus-900/20">
             <div className="flex items-center justify-between text-[9px] font-mono text-nexus-500 uppercase">
                <span>OPA Status</span>
                <span className="text-nexus-success font-bold">Enforced</span>
             </div>
        </div>
      </div>

      {/* MAIN WORKSPACE */}
      <div className="flex-1 flex flex-col min-w-0 w-full relative z-10">

        {/* HEADER BAR */}
        <div className="h-14 sm:h-16 glass border-b border-nexus-700/30 flex items-center justify-between px-3 sm:px-6 z-30">
            <div className="flex items-center gap-3 sm:gap-6">
              <button className="md:hidden text-nexus-500 p-2 hover:bg-nexus-700/30 rounded-lg" onClick={() => setIsSidebarOpen(true)}>
                <Database size={20} />
              </button>
              <div className="flex flex-col">
                  <h1 className="text-[11px] sm:text-xs font-bold tracking-[0.4em] font-mono flex items-center gap-2 uppercase">
                    <Sparkles size={14} className="text-nexus-accent hidden sm:block" />
                    Nexus Core
                  </h1>
                  <div className="flex items-center gap-1.5 mt-0.5">
                    <div className="w-1.5 h-1.5 rounded-full bg-nexus-success shadow-[0_0_8px_#10b981]" />
                    <span className="text-[8px] font-mono text-nexus-500 uppercase tracking-widest hidden xs:block">Secure Build 3.1</span>
                  </div>
              </div>
            </div>

            <div className="flex items-center gap-2 sm:gap-4">
                <div className="hidden xl:flex items-center gap-6 mr-6 text-[9px] font-mono font-bold tracking-tighter">
                    <div className="flex flex-col items-end">
                        <span className="text-nexus-500 text-[8px] uppercase">RTT</span>
                        <span className="text-nexus-accent">{systemMetrics.latency}ms</span>
                    </div>
                </div>

                <div className="flex bg-nexus-900 border border-nexus-700/50 p-1 rounded-xl">
                    <button onClick={() => setMode('flash')} className={`px-2 sm:px-3 py-1 rounded-lg text-[10px] font-bold uppercase transition-all ${mode === 'flash' ? 'bg-nexus-accent/20 text-nexus-accent border border-nexus-accent/30' : 'text-nexus-500 border border-transparent'}`}>
                        <Zap size={12} className="sm:hidden" />
                        <span className="hidden sm:inline">Flash</span>
                    </button>
                    <button onClick={() => setMode('pro')} className={`px-2 sm:px-3 py-1 rounded-lg text-[10px] font-bold uppercase transition-all ${mode === 'pro' ? 'bg-nexus-accent/20 text-nexus-accent border border-nexus-accent/30' : 'text-nexus-500 border border-transparent'}`}>
                        <Cpu size={12} className="sm:hidden" />
                        <span className="hidden sm:inline">Pro</span>
                    </button>
                </div>

                <button onClick={() => setIsMonitorOpen(!isMonitorOpen)} className={`p-2 sm:p-2.5 rounded-xl transition-all border ${isMonitorOpen ? 'border-nexus-accent/50 text-nexus-accent bg-nexus-accent/5 shadow-lg' : 'border-nexus-700/50 text-nexus-500'}`}>
                    <Activity size={18} />
                </button>
            </div>
        </div>

        {/* DIALOG AREA */}
        <div className="flex-1 overflow-y-auto p-4 sm:p-6 lg:p-10 space-y-8 custom-scrollbar">
            {messages.length === 0 && (
                <div className="flex flex-col items-center justify-center min-h-[50vh] text-center animate-in fade-in slide-in-from-top-4 duration-1000">
                    <div className="w-16 h-16 sm:w-20 sm:h-20 bg-nexus-accent/5 rounded-full flex items-center justify-center mb-6 relative">
                        <Bot size={36} className="text-nexus-accent animate-pulse-slow" />
                        <div className="absolute inset-0 border border-nexus-accent/10 rounded-full animate-ping opacity-20" />
                    </div>
                    <h3 className="text-sm sm:text-lg font-mono font-bold tracking-[0.3em] mb-2 uppercase text-gray-400">Interfacing with Nexus</h3>
                    <p className="text-nexus-500 text-[11px] sm:text-xs max-w-xs sm:max-w-sm leading-relaxed font-mono px-4">
                        Grounding intelligence in secure context artifacts via Dual-LLM pattern.
                    </p>
                    <div className="mt-8 flex flex-wrap justify-center gap-3 px-4">
                        <div className="px-3 py-1.5 glass border border-nexus-700/50 rounded-lg text-[9px] font-mono text-nexus-accent uppercase tracking-wider flex items-center gap-2 shadow-xl">
                             <Command size={10} /> OPA Enforced
                        </div>
                        <div className="px-3 py-1.5 glass border border-nexus-700/50 rounded-lg text-[9px] font-mono text-nexus-success uppercase tracking-wider flex items-center gap-2 shadow-xl">
                             <Shield size={10} /> Sandbox Active
                        </div>
                    </div>
                </div>
            )}

            {messages.map((msg) => (
                <div key={msg.id} className={`flex gap-3 sm:gap-6 ${msg.role === 'user' ? 'flex-row-reverse' : ''} animate-in slide-in-from-bottom-2 duration-500`}>
                    <div className={`w-8 h-8 sm:w-10 sm:h-10 rounded-xl flex items-center justify-center shrink-0 border border-nexus-700/50 shadow-xl ${msg.role === 'model' ? 'bg-nexus-900 text-nexus-accent' : 'bg-nexus-800 text-gray-300'}`}>
                        {msg.role === 'model' ? <Bot size={20} className="sm:size-[22px]" /> : <div className="text-[9px] font-mono font-bold">USR</div>}
                    </div>
                    <div className={`max-w-[90%] sm:max-w-[80%] md:max-w-3xl space-y-3 ${msg.role === 'user' ? 'items-end' : ''}`}>
                        <div className={`px-4 sm:px-6 py-4 sm:py-5 rounded-2xl text-sm sm:text-[15px] leading-relaxed border shadow-2xl ${msg.role === 'user' ? 'bg-nexus-accent text-white border-nexus-accent message-frame-user' : 'glass border-nexus-700/40 text-gray-200 message-frame-model'}`}>
                            <ReactMarkdown className="prose prose-invert prose-sm max-w-none break-words" components={{
                                code({node, inline, className, children, ...props}: any) {
                                    const match = /language-(\w+)/.exec(className || '')
                                    return !inline && match ? (
                                        <div className="relative group my-4 sm:my-6">
                                            <div className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                                <span className="text-[8px] font-mono bg-nexus-900/80 px-2 py-1 rounded border border-nexus-700 text-nexus-500 uppercase">{match[1]}</span>
                                            </div>
                                            <div className="rounded-xl overflow-hidden border border-nexus-700/50 shadow-2xl">
                                                <SyntaxHighlighter style={vscDarkPlus} language={match[1]} PreTag="div" {...props} customStyle={{ margin: 0, padding: '1rem', fontSize: '0.8rem', background: 'rgba(5,5,5,0.7)' }}>
                                                    {String(children).replace(/\n$/, '')}
                                                </SyntaxHighlighter>
                                            </div>
                                        </div>
                                    ) : (
                                        <code className="bg-white/10 px-1.5 py-0.5 rounded text-nexus-warning font-mono text-[12px]" {...props}>
                                            {children}
                                        </code>
                                    )
                                }
                            }}>
                                {msg.text}
                            </ReactMarkdown>
                        </div>
                        {msg.role === 'model' && artifacts.filter(a => a.type === 'csv' && msg.text.toLowerCase().includes(a.name.toLowerCase())).map(a => (
                            <div key={a.id} className="w-full">
                                <ChartRenderer artifact={a} />
                            </div>
                        ))}
                    </div>
                </div>
            ))}
            {isProcessing && (
                <div className="flex gap-4 sm:gap-6 animate-pulse">
                     <div className="w-8 h-8 sm:w-10 sm:h-10 rounded-xl bg-nexus-900 border border-nexus-700 flex items-center justify-center">
                        <Loader2 size={18} className="animate-spin text-nexus-accent" />
                    </div>
                    <div className="flex flex-col gap-1 py-1">
                        <div className="flex items-center gap-2 text-[9px] font-mono text-nexus-success uppercase font-bold tracking-widest">
                            <ShieldCheck size={12} /> SECURE_CHANNEL_READY
                        </div>
                        <div className="text-[11px] font-mono text-nexus-500 uppercase tracking-widest flex items-center gap-2">
                            Reasoning {mode}
                            <span className="flex gap-0.5"><span className="w-0.5 h-0.5 bg-nexus-500 rounded-full animate-bounce" /><span className="w-0.5 h-0.5 bg-nexus-500 rounded-full animate-bounce [animation-delay:0.2s]" /></span>
                        </div>
                    </div>
                </div>
            )}
            <div ref={messagesEndRef} />
        </div>

        {/* INPUT MISSION CONTROL */}
